CREATE VIEW `ads_sv_user_cancel_subscription_view` (`user_id` COMMENT "用户id", `shop_item_type` COMMENT "项目类型", `cancel_time` COMMENT "取消时间") AS SELECT `dwd`.`dwd_pay_order_notify`.`user_id`, CASE WHEN (`dwd`.`dwd_pay_order_notify`.`shop_item_id` IN (810)) THEN 'VIP' WHEN (`dwd`.`dwd_pay_order_notify`.`shop_item_id` IN (840)) THEN '签到卡' END AS `shop_item_type`, `dwd`.`dwd_pay_order_notify`.`cancel_time`
FROM `dwd`.`dwd_pay_order_notify`
WHERE ((`dwd`.`dwd_pay_order_notify`.`product_id` = 6833) AND (`dwd`.`dwd_pay_order_notify`.`user_id` > 0)) AND (`dwd`.`dwd_pay_order_notify`.`notify_type` = 3);